/**
 * @param {number[]} rolls
 * @param {number} mean
 * @param {number} n
 * @return {number[]}
 */
var missingRolls = function(rolls, mean, n) {
    let total = rolls.reduce((a, b) => a + b, 0);
    let totalRolls = rolls.length + n;
    let requiredTotal = mean * totalRolls;
    let missingTotal = requiredTotal - total;

    if (missingTotal < n || missingTotal > 6 * n) {
        return [];
    }

    let result = new Array(n).fill(Math.floor(missingTotal / n));
    let remainder = missingTotal % n;

    for (let i = 0; i < remainder; i++) {
        result[i]++;
    }

    return result;
};
